CREATE PROC [dbo].[TR_ORDER_INSERT2]
(
	@id int OUT,
	@order_number nvarchar(50),
	@customer nvarchar(MAX),
	@order_date date,
	@ship_date date,
	@etd date,
	@cont_date date,
	@f_cancelled nvarchar(5),
	@choduyet int,
	@IsLock bit,
	@Finished bit,
	@IsPay bit,
	@IsExample bit,
	@IsPhoi bit,
	@IsUV bit,
	@destination_port nvarchar(50),
	@ship_to nvarchar(50),
	@remark nvarchar(MAX),
	@payment_term nvarchar(200),
	@carton_marking nvarchar(200),
	@cont_qty decimal(18, 3),
	@cust_po_number nvarchar(200),
	@range nvarchar(200),
	@create_date datetime,
	@create_by nvarchar(50),
	@update_date datetime,
	@update_by nvarchar(50),
	@ngay_hangtrang datetime = null,
	@ngay_son datetime = null,
	@ngay_donggoi datetime = null,
	@nguyenlieu nvarchar(200) = null,
	@bemat nvarchar(200) =  null,
	@IsOutsource BIT = NULL,
    @vendor_id nvarchar(50) = null,
	@noisanxuat bit = 1,
	@loaidonhangmau int = null,
	@currency_code nvarchar(10) = null,
	@exchange_rate decimal(18, 3) = null,
	@fsc_id int = null
)
AS
BEGIN
	IF NOT EXISTS (SELECT 1 FROM tr_order WHERE order_number = @order_number)
	BEGIN
		INSERT INTO tr_order
		(
  			order_number,
  			customer,
  			order_date,
  			ship_date,
  			etd,
  			cont_date,
  			f_cancelled,
  			choduyet,
  			IsLock,
  			Finished,
  			IsPay,
  			IsExample,
  			IsPhoi,
  			IsUV,
  			destination_port,
  			ship_to,
  			remark,
  			payment_term,
  			carton_marking,
  			cont_qty,
  			cust_po_number,
  			[range],
  			create_date,
  			create_by,
  			update_date,
  			update_by,
			ngay_hangtrang,
			ngay_son,
			ngay_donggoi,
			nguyenlieu,
			bemat,
			IsOutsource,
			vendor_id,
			noisanxuat, loaidonhangmau,
			currency_code, exchange_rate,
			fsc_id
		)
		VALUES
		(
  			@order_number,
  			@customer,
  			@order_date,
  			@ship_date,
  			@etd,
  			@cont_date,
  			@f_cancelled,
  			@choduyet,
  			@IsLock,
  			@Finished,
  			@IsPay,
  			@IsExample,
  			@IsPhoi,
  			@IsUV,
  			@destination_port,
  			@ship_to,
  			@remark,
  			@payment_term,
  			@carton_marking,
  			@cont_qty,
  			@cust_po_number,
  			@range,
  			@create_date,
  			@create_by,
  			@update_date,
  			@update_by,
			@ngay_hangtrang,
			@ngay_son,
			@ngay_donggoi,
			@nguyenlieu,
			@bemat,
			@IsOutsource,
			@vendor_id,
			@noisanxuat, @loaidonhangmau,
			@currency_code, @exchange_rate,
			@fsc_id
		)
		SET @id = SCOPE_IDENTITY();
	
		EXEC PS_KEHOACH_DONHANG_CREATE @order_number, 'frmKeHoachSanXuatPO2';
	END

	
END
